import { useEffect, useState } from "react"
import { io } from "socket.io-client"
import axios from "axios"

const socket = io("http://localhost:5001")

export default function ChatPage({ user }) {
  const [arr, setArr] = useState([]) // Chat list
  const [sel, setSel] = useState(null) // Selected user
  const [msg, setMsg] = useState("") // Message input
  const [list, setList] = useState([]) // Messages
  const [online, setOnline] = useState([]) // Online users
  const [typingUser, setTypingUser] = useState("")
  const [search, setSearch] = useState("")
  const [searchResult, setSearchResult] = useState(null)
  const [incomingCall, setIncomingCall] = useState(null)
  const [onCall, setOnCall] = useState(false)
  const [currentCallId, setCurrentCallId] = useState(null)

  // Subscribe to notifications on mount
  useEffect(() => {
    if ("serviceWorker" in navigator && "Notification" in window) {
      navigator.serviceWorker.register("/sw.js").catch(err => console.log("SW registration failed:", err))
      
      if (Notification.permission === "default") {
        Notification.requestPermission()
      }

      if (Notification.permission === "granted" && user?.phone) {
        navigator.serviceWorker.ready.then(registration => {
          const subscription = registration.pushManager.getSubscription()
          if (subscription) {
            axios.post("http://localhost:5001/user/subscribe", {
              phone: user.phone,
              subscription
            }).catch(err => console.log("Subscription error:", err))
          }
        })
      }
    }
  }, [user])

  // Load chat list
  useEffect(() => {
    const f = async () => {
      const token = localStorage.getItem("token");
      try {
        const res = await axios.get("http://localhost:5001/chat/getChats", {
          headers: { Authorization: `Bearer ${token}` }
        })
        setArr(res.data)
      } catch (e) {
        console.error("Error loading chats:", e)
      }
    }
    if (user) f()
  }, [user])

  // Load messages for selected user
  const load = async (u) => {
    setSel(u)
    const r = [user.phone, u.phone].sort().join("_")
    socket.emit("join_room", r)
    const token = localStorage.getItem("token");
    try {
      const res = await axios.get(`http://localhost:5001/chat/getMessages/${u.phone}`, {
        headers: { Authorization: `Bearer ${token}` }
      })
      setList(res.data)
      // Mark all messages as delivered and read
      setTimeout(() => {
        res.data.forEach(m => {
          if (m.receiver === user.phone && !m.delivered) {
            socket.emit("message_delivered", { messageId: m._id, room: r })
          }
          if (m.receiver === user.phone && !m.read) {
            socket.emit("message_read", { messageId: m._id, room: r, reader: user.phone })
          }
        })
      }, 100)
    } catch (e) {
      console.error("Error loading messages:", e)
    }
  }

  // Socket listeners
  useEffect(() => {
    socket.emit("user_online", user?.phone)

    socket.on("online_users", setOnline)

    socket.on("receive_message", m => {
      setList(prev => [...prev, m])
      // Auto mark as delivered when received
      if (m.receiver === user.phone && sel?.phone === m.sender) {
        socket.emit("message_delivered", { 
          messageId: m._id, 
          room: m.room 
        })
      }
    })

    socket.on("message_delivered", ({ messageId }) => {
      setList(prev => prev.map(m => 
        m._id === messageId ? { ...m, delivered: true, received: true } : m
      ))
    })

    socket.on("message_read", ({ messageId }) => {
      setList(prev => prev.map(m => 
        m._id === messageId ? { ...m, read: true } : m
      ))
    })

    // Call events
    socket.on("incoming_call", ({ caller, callerName, callId }) => {
      setIncomingCall({ caller, callerName, callId })
      // Play notification sound if available
      if ("Notification" in window && Notification.permission === "granted") {
        new Notification("Incoming Call", {
          body: `${callerName} is calling...`,
          icon: "/phone-icon.png"
        })
      }
    })

    socket.on("call_accepted", ({ callId }) => {
      setOnCall(true)
      setCurrentCallId(callId)
      alert(`Call accepted! (WebRTC implementation needed for actual call)`)
    })

    socket.on("call_rejected", ({ callId }) => {
      alert("Call rejected")
      setOnCall(false)
      setCurrentCallId(null)
    })

    socket.on("call_ended", ({ callId }) => {
      setOnCall(false)
      setCurrentCallId(null)
      alert("Call ended")
    })

    socket.on("call_failed", ({ message }) => {
      alert(message)
    })

    return () => {
      socket.off("online_users")
      socket.off("receive_message")
      socket.off("message_delivered")
      socket.off("message_read")
      socket.off("incoming_call")
      socket.off("call_accepted")
      socket.off("call_rejected")
      socket.off("call_ended")
      socket.off("call_failed")
    }
  }, [user?.phone, sel?.phone])

  // Typing indicator
  useEffect(() => {
    let t
    socket.on("typing", u => {
      setTypingUser(u)
      clearTimeout(t)
      t = setTimeout(() => setTypingUser(""), 2000)
    })
    return () => socket.off("typing")
  }, [])

  // Send message
  const send = () => {
    if (!msg || !sel) return

    const r = [user.phone, sel.phone].sort().join("_")
    const data = {
      sender: user.phone,
      receiver: sel.phone,
      text: msg,
      room: r,
      senderName: user.name
    }

    socket.emit("send_message", data)
    setMsg("")
  }

  // Search user by phone
  const searchUser = async () => {
    if (!search) return
    const token = localStorage.getItem("token");
    try {
      const res = await axios.post("http://localhost:5001/chat/searchUser", 
        { phone: search },
        { headers: { Authorization: `Bearer ${token}` } }
      )
      setSearchResult(res.data)
    } catch (e) {
      console.error("User not found:", e)
      setSearchResult(null)
    }
  }

  // Initiate call
  const initiateCall = () => {
    if (!sel) return
    const callId = `${user.phone}_${Date.now()}`
    socket.emit("initiate_call", {
      caller: user.phone,
      callee: sel.phone,
      callerName: user.name
    })
    setOnCall(true)
    setCurrentCallId(callId)
  }

  // Accept call
  const acceptCall = () => {
    if (!incomingCall) return
    socket.emit("accept_call", {
      callId: incomingCall.callId,
      callee: user.phone,
      caller: incomingCall.caller
    })
    setIncomingCall(null)
  }

  // Reject call
  const rejectCall = () => {
    if (!incomingCall) return
    socket.emit("reject_call", {
      callId: incomingCall.callId,
      caller: incomingCall.caller
    })
    setIncomingCall(null)
  }

  // End call
  const endCall = () => {
    if (!sel || !currentCallId) return
    socket.emit("end_call", {
      callId: currentCallId,
      otherUser: sel.phone
    })
    setOnCall(false)
    setCurrentCallId(null)
  }

  // Render message status indicator
  const renderMessageStatus = (m) => {
    if (m.sender !== user.phone) return null
    
    if (m.read) {
      return <span style={{ color: "blue", fontWeight: "bold", fontSize: 14 }}>✓✓</span>
    } else if (m.delivered && m.received) {
      return <span style={{ color: "gray", fontSize: 14 }}>✓✓</span>
    } else if (m.delivered) {
      return <span style={{ color: "lightgray", fontSize: 14 }}>✓</span>
    } else {
      return <span style={{ color: "lightgray", fontSize: 14 }}>✓</span>
    }
  }

  return (
    <div style={{ display: "flex", height: "100vh", fontFamily: "Arial", position: "relative" }}>

      {/* INCOMING CALL NOTIFICATION */}
      {incomingCall && (
        <div style={{
          position: "fixed",
          top: 20,
          left: "50%",
          transform: "translateX(-50%)",
          backgroundColor: "#fff",
          border: "2px solid #25D366",
          borderRadius: 15,
          padding: 20,
          zIndex: 1000,
          boxShadow: "0 4px 12px rgba(0,0,0,0.15)",
          minWidth: 300,
          textAlign: "center"
        }}>
          <h2>📞 Incoming Call</h2>
          <p style={{ fontSize: 16, marginBottom: 15 }}>{incomingCall.callerName} is calling...</p>
          <div style={{ display: "flex", gap: 10, justifyContent: "center" }}>
            <button
              onClick={acceptCall}
              style={{
                padding: "10px 20px",
                backgroundColor: "#25D366",
                color: "white",
                border: "none",
                borderRadius: 8,
                cursor: "pointer",
                fontWeight: "bold",
                fontSize: 14
              }}
            >
              ✓ Accept
            </button>
            <button
              onClick={rejectCall}
              style={{
                padding: "10px 20px",
                backgroundColor: "#FF4444",
                color: "white",
                border: "none",
                borderRadius: 8,
                cursor: "pointer",
                fontWeight: "bold",
                fontSize: 14
              }}
            >
              ✕ Reject
            </button>
          </div>
        </div>
      )}

      {/* ON CALL INDICATOR */}
      {onCall && (
        <div style={{
          position: "fixed",
          top: 20,
          left: "50%",
          transform: "translateX(-50%)",
          backgroundColor: "#25D366",
          color: "white",
          padding: 10,
          borderRadius: 8,
          zIndex: 999
        }}>
          📞 Call in progress with {sel?.name}
          <button
            onClick={endCall}
            style={{
              marginLeft: 15,
              padding: "5px 15px",
              backgroundColor: "#FF4444",
              color: "white",
              border: "none",
              borderRadius: 5,
              cursor: "pointer"
            }}
          >
            End Call
          </button>
        </div>
      )}

      {/* LEFT PANEL - CHAT LIST & SEARCH */}
      <div style={{ width: "30%", borderRight: "1px solid #ccc", padding: 15, overflowY: "auto", backgroundColor: "#f9f9f9" }}>
        <h3>💬 Chats</h3>
        
        {/* Search bar */}
        <div style={{ marginBottom: 15 }}>
          <input
            type="tel"
            placeholder="Search by phone"
            value={search}
            onChange={e => setSearch(e.target.value)}
            onKeyPress={e => e.key === 'Enter' && searchUser()}
            style={{ 
              width: "100%", 
              padding: 8, 
              marginBottom: 8,
              border: "1px solid #ddd",
              borderRadius: 5,
              boxSizing: "border-box"
            }}
          />
          <button 
            onClick={searchUser} 
            style={{
              width: "100%",
              padding: 8,
              backgroundColor: "#007bff",
              color: "white",
              border: "none",
              borderRadius: 5,
              cursor: "pointer",
              fontWeight: "bold"
            }}
          >
            Search
          </button>
        </div>

        {/* Search result */}
        {searchResult && (
          <div
            onClick={() => {
              load(searchResult)
              setSearchResult(null)
              setSearch("")
            }}
            style={{
              background: "#e3f2fd",
              padding: 10,
              marginBottom: 10,
              borderRadius: 5,
              cursor: "pointer",
              border: "1px solid #90caf9"
            }}
          >
            <strong>🔍 {searchResult.name}</strong>
            <br/>
            <small>{searchResult.phone}</small>
          </div>
        )}

        {/* Chat list */}
        <div style={{ marginTop: 15 }}>
          <h4>Recent Chats</h4>
          {arr.length === 0 ? (
            <p style={{ color: "#999" }}>No chats yet. Search to start a conversation!</p>
          ) : (
            arr.map(u => (
              <div
                key={u._id}
                onClick={() => load(u)}
                style={{
                  cursor: "pointer",
                  padding: 10,
                  marginBottom: 8,
                  borderRadius: 5,
                  backgroundColor: sel?._id === u._id ? "#007bff" : "#fff",
                  color: sel?._id === u._id ? "#fff" : "#000",
                  border: "1px solid #ddd",
                  transition: "all 0.2s"
                }}
              >
                <strong>{u.name}</strong>
                <small style={{ display: "block", fontSize: 12 }}>{u.phone}</small>
                {online.includes(u.phone) && (
                  <small style={{ color: sel?._id === u._id ? "#fff" : "green", fontWeight: "bold" }}>● Online</small>
                )}
              </div>
            ))
          )}
        </div>
      </div>

      {/* RIGHT PANEL - CHAT MESSAGES */}
      <div style={{ width: "70%", display: "flex", flexDirection: "column", padding: 15 }}>
        {sel ? (
          <>
            {/* HEADER WITH CALL OPTION */}
            <div style={{ borderBottom: "1px solid #ccc", paddingBottom: 10, marginBottom: 10, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
              <div>
                <h3>{sel.name}</h3>
                <small style={{ color: online.includes(sel.phone) ? "green" : "#999" }}>
                  {online.includes(sel.phone) ? "🟢 Online" : "🔘 Offline"}
                </small>
              </div>
              <button
                onClick={initiateCall}
                disabled={!online.includes(sel.phone) || onCall}
                style={{
                  padding: "10px 20px",
                  backgroundColor: online.includes(sel.phone) && !onCall ? "#25D366" : "#ccc",
                  color: "white",
                  border: "none",
                  borderRadius: 8,
                  cursor: online.includes(sel.phone) && !onCall ? "pointer" : "not-allowed",
                  fontWeight: "bold",
                  fontSize: 14
                }}
              >
                📞 Call
              </button>
            </div>

            {/* Messages area */}
            <div style={{ flex: 1, overflowY: "auto", marginBottom: 15, backgroundColor: "#f5f5f5", padding: 10, borderRadius: 5 }}>
              {list.length === 0 ? (
                <p style={{ textAlign: "center", color: "#999" }}>Start a conversation</p>
              ) : (
                list.map((m, i) => (
                  <div
                    key={m._id || i}
                    onMouseEnter={() => {
                      if (m.receiver === user.phone && !m.read) {
                        socket.emit("message_read", { 
                          messageId: m._id, 
                          room: m.room, 
                          reader: user.phone 
                        })
                      }
                    }}
                    style={{
                      marginBottom: 10,
                      padding: 10,
                      borderRadius: 8,
                      backgroundColor: m.sender === user.phone ? "#DCF8C6" : "#fff",
                      marginLeft: m.sender === user.phone ? "20%" : 0,
                      marginRight: m.sender !== user.phone ? "20%" : 0,
                      border: "1px solid #ddd"
                    }}
                  >
                    <div>
                      {m.text}
                    </div>
                    <div style={{ fontSize: 12, marginTop: 5, display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                      <span style={{ color: "#999" }}>
                        {new Date(m.createdAt).toLocaleTimeString()}
                      </span>
                      {renderMessageStatus(m)}
                    </div>
                  </div>
                ))
              )}
            </div>

            {typingUser && (
              <div style={{ fontStyle: "italic", color: "#999", marginBottom: 5, fontSize: 13 }}>
                ✏️ {typingUser} is typing...
              </div>
            )}

            {/* Message input */}
            <div style={{ display: "flex", gap: 10 }}>
              <input
                value={msg}
                onChange={e => {
                  setMsg(e.target.value)
                  socket.emit("typing_start", {
                    room: [user.phone, sel.phone].sort().join("_"),
                    user: user.name
                  })
                }}
                onKeyPress={e => e.key === 'Enter' && send()}
                placeholder="Type a message..."
                style={{
                  flex: 1,
                  padding: 10,
                  border: "1px solid #ccc",
                  borderRadius: 5,
                  fontSize: 14
                }}
              />
              <button 
                onClick={send}
                style={{
                  padding: "10px 20px",
                  backgroundColor: "#25D366",
                  color: "white",
                  border: "none",
                  borderRadius: 5,
                  cursor: "pointer",
                  fontWeight: "bold"
                }}
              >
                Send
              </button>
            </div>
          </>
        ) : (
          <div style={{ 
            display: "flex", 
            alignItems: "center", 
            justifyContent: "center", 
            height: "100%",
            color: "#999"
          }}>
            <h3>👈 Select a chat to start messaging</h3>
          </div>
        )}
      </div>
    </div>
  )
}
